### 5. 단위 테스트 (핵심)

**`/user-service/src/test/kotlin/com/maum/backend/service/UserServiceTest.kt`**

```kotlin
package com.maum.backend.service

import com.maum.backend.domain.follow.Follow
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.NotFollowingException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.repository.FollowRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.DisplayName
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.never
import org.mockito.Mockito.verify
import org.mockito.Mockito.`when`
import org.mockito.junit.jupiter.MockitoExtension
import java.time.LocalDateTime

@ExtendWith(MockitoExtension::class)
@DisplayName("UserService 팔로우 기능 단위 테스트")
class UserServiceTest {

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // ─────────────────────────────────────────────
    // 테스트 픽스처
    // ─────────────────────────────────────────────
    private val followerId = "user-A"
    private val followeeId = "user-B"
    private val fixedTime = LocalDateTime.of(2026, 2, 28, 12, 0, 0)

    private fun buildFollow(
        followerId: String = this.followerId,
        followeeId: String = this.followeeId,
        createdAt: LocalDateTime = fixedTime
    ) = Follow(followerId = followerId, followeeId = followeeId, createdAt = createdAt)

    // ─────────────────────────────────────────────
    // follow()
    // ─────────────────────────────────────────────
    @Nested
    @DisplayName("follow() - 팔로우 처리")
    inner class FollowTest {

        @Test
        fun `should follow successfully when not yet following`() {
            // given
            val follow = buildFollow()
            `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
                .thenReturn(false)
            `when`(followRepository.save(Follow(followerId, followeeId, follow.createdAt)))
                .thenReturn(follow)
            `when`(followRepository.save(org.mockito.kotlin.any()))
                .thenReturn(follow)

            // when
            val result = userService.follow(followerId, followeeId)

            // then
            assertThat(result.followerId).isEqualTo(followerId)
            assertThat(result.followeeId).isEqualTo(followeeId)
            verify(followRepository).existsByFollowerIdAndFolloweeId(followerId, followeeId)
            verify(followRepository).save(org.mockito.kotlin.any())
        }

        @Test
        fun `should throw SelfFollowException when follower and followee are the same user`() {
            // given
            val sameUserId = "user-A"

            // when & then
            assertThrows<SelfFollowException> {
                userService.follow(sameUserId, sameUserId)
            }

            // repository는 호출되지 않아야 한다
            verify(followRepository, never())
                .existsByFollowerIdAndFolloweeId(org.mockito.kotlin.any(), org.mockito.kotlin.any())
            verify(followRepository, never())
                .save(org.mockito.kotlin.any())
        }

        @Test
        fun `should throw AlreadyFollowingException when already following`() {
            // given
            `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
                .thenReturn(true)

            // when & then
            assertThrows<AlreadyFollowingException> {
                userService.follow(followerId, followeeId)
            }

            verify(followRepository, never()).save(org.mockito.kotlin.any())
        }

        @Test
        fun `should throw SelfFollowException message contains userId`() {
            // given
            val userId = "user-self"

            // when
            val exception = assertThrows<SelfFollowException> {
                userService.follow(userId, userId)
            }

            // then
            assertThat(exception.message).contains(userId)
        }
    }

    // ─────────────────────────────────────────────
    // unfollow()
    // ─────────────────────────────────────────────
    @Nested
    @DisplayName("unfollow() - 언팔로우 처리")
    inner class UnfollowTest {

        @Test
        fun `should unfollow successfully when following`() {
            // given
            `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
                .thenReturn(true)

            // when
            userService.unfollow(followerId, followeeId)

            // then
            verify(followRepository).delete(followerId, followeeId)
        }

        @Test
        fun `should throw NotFollowingException when not following`() {
            // given
            `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
                .thenReturn(false)

            // when & then
            assertThrows<NotFollowingException> {
                userService.unfollow(followerId, followeeId)
            }

            verify(followRepository, never()).delete(org.mockito.kotlin.any(), org.mockito.kotlin.any())
        }

        @Test
        fun `should throw NotFollowingException message contains follower and followee id`() {
            // given
            `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
                .thenReturn(false)

            // when
            val exception = assertThrows<NotFollowingException> {
                userService.unfollow(followerId, followeeId)
            }

            // then
            assertThat(exception.message).contains(followerId)
            assertThat(exception.message).contains(followeeId)
        }
    }

    // ─────────────────────────────────────────────
    // getFollowers()
    // ─────────────────────────────────────────────
    @Nested
    @DisplayName("getFollowers() - 팔로워 목록 조회")
    inner class GetFollowersTest {

        @Test
        fun `should return follower list when followers exist`() {
            // given
            val userId = "user-B"
            val followers = listOf(
                buildFollow(followerId = "user-A", followeeId = userId),
                buildFollow(followerId = "user-C", followeeId = userId)
            )
            `when`(followRepository.findAllByFolloweeId(userId)).thenReturn(followers)

            // when
            val result = userService.getFollowers(userId)

            // then
            assertThat(result).hasSize(2)
            assertThat(result).allMatch { it.followeeId == userId }
            verify(followRepository).findAllByFolloweeId(userId)
        }

        @Test
        fun `should return empty list when no followers exist`() {
            // given
            val userId = "user-lonely"
            `when`(followRepository.findAllByFolloweeId(userId)).thenReturn(emptyList())

            // when
            val result = userService.getFollowers(userId)

            // then
            assertThat(result).isEmpty()
            verify(followRepository).findAllByFolloweeId(userId)
        }
    }

    // ─────────────────────────────────────────────
    // getFollowings()
    // ─────────────────────────────────────────────
    @Nested
    @DisplayName("getFollowings() - 팔로잉 목록 조회")
    inner class GetFollowingsTest {

        @Test
        fun `should return following list when followings exist`() {
            // given
            val userId = "user-A"
            val followings = listOf(
                buildFollow(followerId = userId, followeeId = "user-B"),
                buildFollow(followerId = userId, followeeId = "user-C"),
                buildFollow(followerId = userId, followeeId = "user-D")
            )
            `when`(followRepository.findAllByFollowerId(userId)).thenReturn(followings)

            // when
            val result = userService.getFollowings(userId)

            // then
            assertThat(result).hasSize(3)
            assertThat(result).allMatch { it.followerId == userId }
            verify(followRepository).findAllByFollowerId(userId)
        }

        @Test
        fun `should return empty list when no followings exist`() {
            // given
            val userId = "user-new"
            `when`(followRepository.findAllByFollowerId(userId)).thenReturn(emptyList())

            // when
            val result = userService.getFollowings(userId)

            // then
            assertThat(result).isEmpty()
        }
    }

    // ─────────────────────────────────────────────
    // getFollowerCount() / getFollowingCount()
    // ─────────────────────────────────────────────
    @Nested
    @DisplayName("getFollowerCount() / getFollowingCount() - 팔로우 수 조회")
    inner class FollowCountTest {

        @Test
        fun `should return correct follower count`() {
            // given
            val userId = "user-popular"
            `when`(followRepository.countByFolloweeId(userId)).thenReturn(100L)

            // when
            val count = userService.getFollowerCount(userId)

            // then
            assertThat(count).isEqualTo(100L)
            verify(followRepository).countByFolloweeId(userId)
        }

        @Test
        fun `should return zero when no followers`() {
            // given
            val userId = "user-new"
            `when`(followRepository.countByFolloweeId(userId)).thenReturn(0L)

            // when
            val count = userService.getFollowerCount(userId)

            // then
            assertThat(count).isZero()
        }

        @Test
        fun `should return correct following count`() {
            // given
            val userId = "user-A"
            `when`(followRepository.countByFollowerId(userId)).thenReturn(50L)

            // when
            val count = userService.getFollowingCount(userId)

            // then
            assertThat(count).isEqualTo(50L)
            verify(followRepository).countByFollowerId(userId)
        }

        @Test
        fun `should return zero when not following anyone`() {
            // given
            val userId = "user-isolated"
            `when`(followRepository.countByFollowerId(userId)).thenReturn(0L)

            // when
            val count = userService.getFollowingCount(userId)

            // then
            assertThat(count).isZero()
        }
    }

    // ─────────────────────────────────────────────
    // isFollowing()
    // ─────────────────────────────────────────────
    @Nested
    @DisplayName("isFollowing() - 팔로우 여부 확인")
    inner class IsFollowingTest {

        @Test
        fun `should return true when following`() {
            // given
            `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
                .thenReturn(true)

            // when
            val result = userService.isFollowing(followerId, followeeId)

            // then
            assertThat(result).isTrue()
        }

        @Test
        fun `should return false when not following`() {
            // given
            `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
                .thenReturn(false)

            // when
            val result = userService.isFollowing(followerId, followeeId)

            // then
            assertThat(result).isFalse()
        }

        @Test
        fun `should return false when checking reverse direction of follow`() {
            // given: A → B 팔로우는 존재하지만, B → A 는 없는 경우
            `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
                .thenReturn(true)
            `when`(followRepository.existsByFollowerIdAndFolloweeId(followeeId, followerId))
                .thenReturn(false)

            // when
            val forwardResult = userService.isFollowing(followerId, followeeId)   // A → B
            val reverseResult = userService.isFollowing(followeeId, followerId)   // B → A

            // then
            assertThat(forwardResult).isTrue()
            assertThat(reverseResult).isFalse()
        }
    }
}
```

