### 4. 서비스 코드

**`/user-service/src/main/kotlin/com/maum/backend/service/UserService.kt`**

```kotlin
package com.maum.backend.service

import com.maum.backend.domain.follow.Follow
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.NotFollowingException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.repository.FollowRepository

class UserService(
    private val followRepository: FollowRepository
) {

    /**
     * 팔로우 처리
     * - 자기 자신 팔로우 불가
     * - 이미 팔로우 중이면 예외
     */
    fun follow(followerId: String, followeeId: String): Follow {
        if (followerId == followeeId) {
            throw SelfFollowException(followerId)
        }

        if (followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw AlreadyFollowingException(followerId, followeeId)
        }

        val follow = Follow(followerId = followerId, followeeId = followeeId)
        return followRepository.save(follow)
    }

    /**
     * 언팔로우 처리
     * - 팔로우 관계가 없으면 예외
     */
    fun unfollow(followerId: String, followeeId: String) {
        if (!followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw NotFollowingException(followerId, followeeId)
        }
        followRepository.delete(followerId, followeeId)
    }

    /**
     * 팔로워 목록 조회 (나를 팔로우하는 사람들)
     */
    fun getFollowers(userId: String): List<Follow> {
        return followRepository.findAllByFolloweeId(userId)
    }

    /**
     * 팔로잉 목록 조회 (내가 팔로우하는 사람들)
     */
    fun getFollowings(userId: String): List<Follow> {
        return followRepository.findAllByFollowerId(userId)
    }

    /**
     * 팔로워 수 조회
     */
    fun getFollowerCount(userId: String): Long {
        return followRepository.countByFolloweeId(userId)
    }

    /**
     * 팔로잉 수 조회
     */
    fun getFollowingCount(userId: String): Long {
        return followRepository.countByFollowerId(userId)
    }

    /**
     * 팔로우 여부 확인
     */
    fun isFollowing(followerId: String, followeeId: String): Boolean {
        return followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)
    }
}
